const results = $input.first().json.response.results;

const messages = results
  .filter(msg => msg.Content)
  .sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp))
  .map(msg => ({ role: msg.role, content: msg.Content.trim() }));

// Get conversation_id from first message (all should have same conversation_id)
const sessionId = results[0]?.conversation_id || '';

return [{
  json: {
    systemInstructions: "Your instructions...",
    conversation: messages.slice(-6),  // Last 6 messages
    session_id: sessionId  // Renamed variable
  }
}];

